-                    filteredExternal[specificServer] = serverTools
-                }
-            } else {
-                // Show all external tools
-                filteredExternal = tools.external
-            }
-        }
-
-        return CategorizedTools(native: filteredNative, external: filteredExternal)
-    }
-
-    /// Sort tools within categories
